"use client";

/* ════════════════════════════════════════════════════════════════════════
   BridgeAddCategory — write surface for creating a new category.
   Ported from /Users/mac/Downloads/MAGELLAN UX/Bridge/Opertation/
   magellan-bridge-add-category.html

   Pattern:
   - Drop-to-fill zone (sheet / list)
   - "The category" card: name, parent dropdown, kind segmented,
     auto-classify rule (live-drafted from inputs), starting SKU chips
   - "What this creates" live consequence read — 2 tiers:
       Capital share (SKUs captured, capital, share of inventory, blended CM1)
       Health (cover, velocity, slow movers, supplier spread)
   ════════════════════════════════════════════════════════════════════════ */

import { useMemo, useState } from "react";
import { useBridge } from "@/features/bridge/hooks/use-bridge";

type Kind = "Sellable" | "Component" | "Packaging";

const PARENTS = [
  "Top-level (no parent)",
  "Bouquets",
  "Arrangements",
  "Plants",
  "Cakes",
  "Chocolates",
  "Gift Baskets",
];

const STARTING_SKUS = [
  "Pastel Tulip Bouquet",
  "Red Rose Dozen",
  "Sunflower Bundle",
  "Hydrangea Stems",
];

export function BridgeAddCategory() {
  const { setPage } = useBridge();

  const [name, setName] = useState("");
  const [parent, setParent] = useState<string | null>(null);
  const [kind, setKind] = useState<Kind>("Sellable");
  const [rule, setRule] = useState("");
  const [openMenu, setOpenMenu] = useState<"parent" | null>(null);
  const [created, setCreated] = useState(false);

  // Auto-draft the classify rule from the name if the user hasn't edited it
  const draftedRule = useMemo(() => {
    if (!name.trim()) return "";
    const slug = name.toLowerCase().split(/\s+/)[0];
    return `name contains "${slug}"`;
  }, [name]);
  const effectiveRule = rule || draftedRule;

  const filled = [name, kind, effectiveRule].filter(Boolean).length;
  const enough = filled >= 2;

  // Mocked consequence reads — in the demo these come from matched SKUs.
  // They mostly stay stable; nudge them slightly when name/kind changes
  // so the surface feels reactive.
  const skuCount = name ? 9 : STARTING_SKUS.length;
  const capital = kind === "Component" ? "$74K" : kind === "Packaging" ? "$32K" : "$186K";
  const share = kind === "Component" ? "6%" : kind === "Packaging" ? "2%" : "14%";
  const blendedCM1 = kind === "Sellable" ? "71%" : "—";
  const cover = "~16 days";
  const velocity = "~21";
  const slow = "1";
  const suppliers = "3";

  const create = () => {
    setCreated(true);
    setTimeout(() => {
      setCreated(false);
      setPage("home");
    }, 1500);
  };

  return (
    <div className="bridge-content">
      <div className="bridge-page-head">
        <div className="bridge-page-head-icon">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
            <rect x="3" y="3" width="7" height="7" rx="1" />
            <rect x="14" y="3" width="7" height="7" rx="1" />
            <rect x="3" y="14" width="7" height="7" rx="1" />
            <rect x="14" y="14" width="7" height="7" rx="1" />
          </svg>
        </div>
        <div>
          <div className="bridge-page-head-title">Add Category</div>
          <div className="bridge-page-head-sub">
            Create a bucket SKUs sort into — Magellan sets an auto-classify rule and shows the capital it will hold.
          </div>
        </div>
      </div>

      {/* Drop to fill */}
      <div className="bridge-ni-drop">
        <div className="bridge-ni-drop-icon">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.7" strokeLinecap="round" strokeLinejoin="round">
            <path d="M12 16 L12 4 M12 4 L8 8 M12 4 L16 8" />
            <path d="M4 14 L4 19 A1 1 0 0 0 5 20 L19 20 A1 1 0 0 0 20 19 L20 14" />
          </svg>
        </div>
        <div className="bridge-ni-drop-text">
          <div className="bridge-ni-drop-title">
            Drop a category list or example items — or fill it in below
          </div>
          <div className="bridge-ni-drop-sub">
            Magellan reads it, names the category, and drafts an auto-classify rule. Everything stays editable.
          </div>
        </div>
        <button className="bridge-ni-drop-browse" type="button">Choose file</button>
      </div>

      {/* The category card */}
      <div className="bridge-ni-card">
        <div className="bridge-ni-card-head">
          <span className="bridge-ni-section">The category</span>
          <span className="bridge-ni-source manual">✏ Entering manually</span>
        </div>
        <div className="bridge-ni-grid">
          <div className="bridge-ni-field bridge-ni-span">
            <span className="bridge-ni-label">Category name</span>
            <input
              className="bridge-ni-input"
              type="text"
              placeholder="e.g. Seasonal Bouquets"
              value={name}
              onChange={(e) => setName(e.target.value)}
            />
          </div>

          <div className="bridge-ni-field">
            <span className="bridge-ni-label">Sits under</span>
            <div
              className={`bridge-ni-select${openMenu === "parent" ? " open" : ""}`}
              onClick={() => setOpenMenu((m) => (m === "parent" ? null : "parent"))}
            >
              <span className={parent ? "" : "ph"}>{parent ?? "Top-level (no parent)"}</span>
              <span className="chev">▾</span>
              {openMenu === "parent" && (
                <div className="bridge-ni-menu open">
                  {PARENTS.map((p) => (
                    <div
                      key={p}
                      className="bridge-ni-menu-item"
                      onClick={(e) => {
                        e.stopPropagation();
                        setParent(p);
                        setOpenMenu(null);
                      }}
                    >
                      {p}
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>

          <div className="bridge-ni-field">
            <span className="bridge-ni-label">Kind</span>
            <div className="bridge-ni-seg">
              {(["Sellable", "Component", "Packaging"] as Kind[]).map((k) => (
                <button
                  key={k}
                  className={kind === k ? "on" : ""}
                  onClick={() => setKind(k)}
                  type="button"
                >
                  {k}
                </button>
              ))}
            </div>
          </div>

          <div className="bridge-ni-field bridge-ni-span">
            <span className="bridge-ni-label">
              Auto-classify rule
              <span className="bridge-ni-hint">Magellan drafts this — edit freely</span>
            </span>
            <input
              className="bridge-ni-input"
              type="text"
              placeholder={'e.g. name contains "bouquet" or "bunch", supplier is a florist'}
              value={effectiveRule}
              onChange={(e) => setRule(e.target.value)}
            />
          </div>

          <div className="bridge-ni-field bridge-ni-span">
            <span className="bridge-ni-label">
              Starting SKUs
              <span className="bridge-ni-hint">SKUs the rule already matches</span>
            </span>
            <div className="bridge-ni-chips">
              {STARTING_SKUS.map((s) => (
                <span key={s} className="bridge-ni-chip">{s}</span>
              ))}
              <span className="bridge-ni-chip more">+5 more</span>
            </div>
          </div>
        </div>
      </div>

      {/* What this creates */}
      <div className="bridge-ni-outcome">
        <div className="bridge-ni-outcome-head">
          <span className="m-mark">M</span> What this creates
          <span className="bridge-ni-outcome-prov firm">Computed from matched SKUs</span>
        </div>

        <div className="bridge-ni-outcome-tier">
          <div className="bridge-ni-tier-label">Capital share</div>
          <div className="bridge-ni-outcome-grid">
            <div className="bridge-ni-out">
              <span className="k">SKUs captured</span>
              <span className="v">
                {skuCount} <small>items</small>
              </span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">Capital in category</span>
              <span className="v">{capital}</span>
              <span className="kk">on-hand × landed</span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">Share of inventory</span>
              <span className="v">
                {share} <small>of $1.3M</small>
              </span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">Blended CM1</span>
              <span className={`v${kind === "Sellable" ? " good" : ""}`}>{blendedCM1}</span>
              <span className="kk">weighted by value</span>
            </div>
          </div>
        </div>

        <div className="bridge-ni-outcome-tier">
          <div className="bridge-ni-tier-label">Health</div>
          <div className="bridge-ni-outcome-grid">
            <div className="bridge-ni-out">
              <span className="k">Avg days of cover</span>
              <span className="v">{cover}</span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">Velocity</span>
              <span className="v">
                {velocity} <small>/day</small>
              </span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">Slow movers</span>
              <span className="v">
                {slow} <small>SKU</small>
              </span>
              <span className="kk">flagged for review</span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">Supplier spread</span>
              <span className="v">
                {suppliers} <small>suppliers</small>
              </span>
            </div>
          </div>
        </div>

        <div className="bridge-ni-outcome-note">
          Category capital and CM1 are computed from the SKUs the rule matches — this is real, not a guess. Once created, it appears in <b>Categories</b> (capital share &amp; rebalancing) and scopes the <b>Inventory Ledger</b> and <b>Velocity</b> views.
        </div>
      </div>

      {/* Commit */}
      <div className="bridge-ni-commit">
        <div className="bridge-ni-commit-note">
          This drafts the category and its rule — <b>nothing is reclassified</b> until you confirm. Reversible.
        </div>
        <div className="bridge-ni-commit-btns">
          <button className="bridge-ni-cancel" type="button" onClick={() => setPage("home")}>
            Cancel
          </button>
          <button
            className={`bridge-ni-create${created ? " done" : ""}`}
            type="button"
            onClick={create}
            disabled={!enough || created}
          >
            {created ? "Category drafted ✓" : "Create category →"}
          </button>
        </div>
      </div>
    </div>
  );
}
